// YOUR_AWS_SECRET_KEY_HERE===
// USER CONFIGURATION via Environment Variables
// YOUR_AWS_SECRET_KEY_HERE===
const USER_LAT = parseFloat($vars.USER_LAT) || 35.6762;
const USER_LON = parseFloat($vars.USER_LON) || 139.6503;
const USER_LOCATION_NAME = $vars.USER_LOCATION_NAME || 'Tokyo';
const VISIBILITY_RADIUS_KM = parseInt($vars.VISIBILITY_RADIUS_KM) || 800;

// YOUR_AWS_SECRET_KEY_HERE===
// Get data from previous nodes
// YOUR_AWS_SECRET_KEY_HERE===
const issBasic = $('Get ISS Position1').first().json;
const issDetailed = $('Get ISS Detailed (N2YO)').first().json;
const tiangong = $('Get Tiangong Position').first().json;

