// Process ISS
// YOUR_AWS_SECRET_KEY_HERE===
const issLat = parseFloat(issBasic.iss_position.latitude);
const issLon = parseFloat(issBasic.iss_position.longitude);
const issDistance = haversineDistance(USER_LAT, USER_LON, issLat, issLon);
const issBearing = calculateBearing(USER_LAT, USER_LON, issLat, issLon);
const issAltitude = issDetailed?.positions?.[0]?.sataltitude || 408;
const issElevation = Math.atan2(issAltitude, issDistance) * 180 / Math.PI;

// YOUR_AWS_SECRET_KEY_HERE===
// Process Tiangong
// YOUR_AWS_SECRET_KEY_HERE===
let tiangongData = null;
if (tiangong?.positions?.[0]) {
  const tgPos = tiangong.positions[0];
  const tgDistance = haversineDistance(USER_LAT, USER_LON, tgPos.satlatitude, tgPos.satlongitude);
  const tgBearing = calculateBearing(USER_LAT, USER_LON, tgPos.satlatitude, tgPos.satlongitude);
  tiangongData = {
    name: 'Tiangong (天宮)',
    noradId: 48274,
    latitude: tgPos.satlatitude,
    longitude: tgPos.satlongitude,
    altitude: tgPos.sataltitude,
    distance: Math.round(tgDistance),
    bearing: Math.round(tgBearing),
    direction: bearingToDirection(tgBearing),
    directionJP: bearingToDirectionJP(tgBearing),
    elevation: Math.round(Math.atan2(tgPos.sataltitude, tgDistance) * 180 / Math.PI),
    isNearby: tgDistance <= VISIBILITY_RADIUS_KM
  };
}

const satellites = [
  {
    name: 'ISS (国際宇宙ステーション)',
    noradId: 25544,
    latitude: issLat,
    longitude: issLon,
    altitude: Math.round(issAltitude),
    distance: Math.round(issDistance),
    bearing: Math.round(issBearing),
    direction: bearingToDirection(issBearing),
    directionJP: bearingToDirectionJP(issBearing),
    elevation: Math.round(issElevation),
    isNearby: issDistance <= VISIBILITY_RADIUS_KM,
    velocity: issDetailed?.positions?.[0]?.velocity || 27600
  }
];

if (tiangongData) satellites.push(tiangongData);

const nearbySatellites = satellites.filter(s => s.isNearby);

return [{
  json: {
    satellites,
    nearbySatellites,
    hasNearby: nearbySatellites.length > 0,
    userLocation: {
      name: USER_LOCATION_NAME,
      latitude: USER_LAT,
      longitude: USER_LON
    },
    visibilityRadius: VISIBILITY_RADIUS_KM,
    timestamp: new Date().toISOString(),
    timestampJP: new Date().toLocaleString('ja-JP', { timeZone: 'Asia/Tokyo' })
  }
}];

const mainData = $('Analyze Observation Conditions1').first().json;
const triviaResponse = $input.first().json.text || $input.first().json.output;

let trivia = {};
try {
  const jsonMatch = triviaResponse.match(/\{[\s\S]*\}/);
  if (jsonMatch) trivia = JSON.parse(jsonMatch[0]);
} catch (e) {
  trivia = {
    trivia_jp: 'ISSは地球を約90分で1周し、1日に16回の日の出を見ることができます。',
    trivia_en: 'The ISS orbits Earth in about 90 minutes, allowing astronauts to see 16 sunrises per day.',
    category: 'ISS',
    emoji: '🌅'
  };
}

// Build notification message
const sat = mainData.nearbySatellites[0];
const loc = mainData.userLocation;

let message = `🛰️ **宇宙ステーション接近アラート**\n\n`;
message += `📍 **観測地:** ${loc.name}\n`;
message += `⏰ **検出時刻:** ${mainData.timestampJP}\n\n`;

message += `━━━━━━━━━━━━━━━━━━━━\n`;
message += `🎯 **接近中の衛星**\n`;
message += `━━━━━━━━━━━━━━━━━━━━\n\n`;

mainData.nearbySatellites.forEach(s => {
  message += `**${s.name}**\n`;
  message += `  📏 距離: ${s.distance.toLocaleString()} km\n`;
  message += `  🧭 方角: ${s.directionJP} (${s.bearing}°)\n`;
  message += `  📐 仰角: ${s.elevation}°\n`;
  message += `  🚀 高度: ${s.altitude} km\n\n`;
});

message += `━━━━━━━━━━━━━━━━━━━━\n`;
message += `${mainData.observation.recommendation} **観測条件**\n`;
message += `━━━━━━━━━━━━━━━━━━━━\n\n`;
message += `  📊 スコア: ${mainData.observation.score}/100\n`;
message += `  ${mainData.observation.timeCondition}\n`;
message += `  ${mainData.observation.conditions.join(', ')}\n`;
message += `  🌡️ 気温: ${mainData.weather.temperature}°C\n`;
message += `  ☁️ 雲量: ${mainData.weather.cloudiness}%\n\n`;

if (mainData.photography.iso) {
  message += `━━━━━━━━━━━━━━━━━━━━\n`;
  message += `📸 **撮影設定ガイド**\n`;
  message += `━━━━━━━━━━━━━━━━━━━━\n\n`;
  message += `  ISO: ${mainData.photography.iso}\n`;
  message += `  絞り: ${mainData.photography.aperture}\n`;
  message += `  シャッター: ${mainData.photography.shutter}\n`;
  message += `  💡 ${mainData.photography.tips}\n\n`;
}

message += `━━━━━━━━━━━━━━━━━━━━\n`;
message += `👨‍🚀 **現在宇宙にいる人々**\n`;
message += `━━━━━━━━━━━━━━━━━━━━\n\n`;
message += `  🌍 合計: ${mainData.astronauts.totalInSpace}人\n`;
if (mainData.astronauts.iss.length > 0) {
  message += `  🇺🇸 ISS: ${mainData.astronauts.iss.map(a => a.name).join(', ')}\n`;
}
if (mainData.astronauts.tiangong.length > 0) {
  message += `  🇨🇳 天宮: ${mainData.astronauts.tiangong.map(a => a.name).join(', ')}\n`;
}

message += `\n━━━━━━━━━━━━━━━━━━━━\n`;
message += `${trivia.emoji} **今日の宇宙トリビア**\n`;
message += `━━━━━━━━━━━━━━━━━━━━\n\n`;
message += `${trivia.trivia_jp}\n\n`;

message += `🌍 **3Dマップで確認:**\n`;
message += `https://earth.google.com/web/search/${sat.latitude},${sat.longitude}`;

return [{
  json: {
    ...mainData,
    trivia,
    notificationMessage: message,
    shortMessage: `🛰️ ${sat.name}接近中！ ${sat.directionJP}方向 ${sat.distance}km`,
    alertType: 'satellite_overhead'
  }
}];

const issPasses = $('Get ISS Pass Predictions').first().json.passes || [];
const tiangongPasses = $('Get Tiangong Predictions').first().json.passes || [];

function formatPass(pass, satName) {
  const startTime = new Date(pass.startUTC * 1000);
  const endTime = new Date(pass.endUTC * 1000);
  const duration = Math.round((pass.endUTC - pass.startUTC) / 60);

  return {
    satellite: satName,
    startTime: startTime.toISOString(),
    startTimeJP: startTime.toLocaleString('ja-JP', { timeZone: 'Asia/Tokyo' }),
    endTime: endTime.toISOString(),
    duration: duration,
    maxElevation: pass.maxEl,
    startAzimuth: pass.startAz,
    startDirection: getDirection(pass.startAz),
    endAzimuth: pass.endAz,
    endDirection: getDirection(pass.endAz),
    magnitude: pass.mag || 'N/A',
    brightness: getBrightness(pass.mag)
  };
}

function getDirection(az) {
  const dirs = ['北', '北東', '東', '南東', '南', '南西', '西', '北西'];
  return dirs[Math.round(az / 45) % 8];
}

function getBrightness(mag) {
  if (mag === undefined || mag === 'N/A') return '明るさ不明';
  if (mag < -3) return '⭐⭐⭐ 非常に明るい';
  if (mag < -1) return '⭐⭐ 明るい';
  if (mag < 1) return '⭐ 見える';
  return '暗い（双眼鏡推奨）';
}

const allPasses = [
  ...issPasses.map(p => formatPass(p, 'ISS')),
  ...tiangongPasses.map(p => formatPass(p, 'Tiangong'))
].sort((a, b) => new Date(a.startTime) - new Date(b.startTime));

const next7Days = allPasses.slice(0, 14);

// Find best passes (high elevation, good brightness)
const bestPasses = allPasses
  .filter(p => p.maxElevation >= 40)
  .slice(0, 5);

return [{
  json: {
    predictions: next7Days,
    bestPasses,
    totalPasses: allPasses.length,
    userLocation: $vars.USER_LOCATION_NAME || 'Tokyo',
    generatedAt: new Date().toISOString()
  }
}];

const data = $input.first().json;

let message = `🗓️ **今週の宇宙ステーション可視予報**\n`;
message += `📍 観測地: ${data.userLocation}\n`;
message += `📅 生成日時: ${new Date().toLocaleString('ja-JP', { timeZone: 'Asia/Tokyo' })}\n\n`;

if (data.bestPasses.length > 0) {
  message += `━━━━━━━━━━━━━━━━━━━━\n`;
  message += `⭐ **おすすめ観測機会 TOP ${data.bestPasses.length}**\n`;
  message += `━━━━━━━━━━━━━━━━━━━━\n\n`;

  data.bestPasses.forEach((pass, i) => {
    message += `**${i + 1}. ${pass.satellite}**\n`;
    message += `  📅 ${pass.startTimeJP}\n`;
    message += `  ⏱️ ${pass.duration}分間\n`;
    message += `  📐 最大仰角: ${pass.maxElevation}°\n`;
    message += `  🧭 ${pass.startDirection} → ${pass.endDirection}\n`;
    message += `  ${pass.brightness}\n\n`;
  });
}

message += `━━━━━━━━━━━━━━━━━━━━\n`;
message += `📋 **全予報 (次の7日間)**\n`;
message += `━━━━━━━━━━━━━━━━━━━━\n\n`;

data.predictions.slice(0, 10).forEach(pass => {
  const icon = pass.satellite === 'ISS' ? '🇺🇸' : '🇨🇳';
  message += `${icon} **${pass.startTimeJP}**\n`;
  message += `   ${pass.satellite} | ${pass.duration}分 | 仰角${pass.maxElevation}° | ${pass.startDirection}→${pass.endDirection}\n\n`;
});

if (data.predictions.length > 10) {
  message += `... 他 ${data.predictions.length - 10} 件の通過があります\n\n`;
}

message += `💡 **観測のコツ:**\n`;
message += `• 仰角40°以上が最も見やすい\n`;
message += `• 薄明時（日没後/日出前）がベスト\n`;
message += `• 明るい点が一定速度で移動するのを探す\n`;

return [{
  json: {
    ...data,
    predictionMessage: message,
    calendarEvents: data.bestPasses.map(p => ({
      title: `🛰️ ${p.satellite} 観測チャンス`,
      start: p.startTime,
      end: p.endTime,
      description: `方角: ${p.startDirection}→${p.endDirection}, 仰角: ${p.maxElevation}°`
    }))
  }
}];

const items = $input.all();
const now = new Date();
const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

const weeklyData = items.filter(item => {
  const ts = new Date(item.json.timestamp);
  return ts >= weekAgo;
});

const stats = {
  totalSightings: weeklyData.length,
  observableSightings: weeklyData.filter(d => d.json.could_observe === 'true').length,
  avgScore: 0,
  satelliteBreakdown: {},
  directionBreakdown: {},
  weatherBreakdown: {},
  bestSighting: null,
  triviaCategories: {}
};

let totalScore = 0;
let bestScore = 0;

weeklyData.forEach(item => {
  const d = item.json;
  const score = parseInt(d.observation_score) || 0;
  totalScore += score;

  if (score > bestScore) {
    bestScore = score;
    stats.bestSighting = d;
  }

  // Satellite breakdown
  const sat = d.satellite || 'Unknown';
  stats.satelliteBreakdown[sat] = (stats.satelliteBreakdown[sat] || 0) + 1;

  // Direction breakdown
  const dir = d.direction || 'Unknown';
  stats.directionBreakdown[dir] = (stats.directionBreakdown[dir] || 0) + 1;

  // Weather breakdown
  const weather = d.weather || 'Unknown';
  stats.weatherBreakdown[weather] = (stats.weatherBreakdown[weather] || 0) + 1;

  // Trivia categories
  const trivia = d.trivia_category || 'General';
  stats.triviaCategories[trivia] = (stats.triviaCategories[trivia] || 0) + 1;
});

stats.avgScore = weeklyData.length > 0 ? Math.round(totalScore / weeklyData.length) : 0;
stats.successRate = weeklyData.length > 0 ? Math.round((stats.observableSightings / weeklyData.length) * 100) : 0;

return [{ json: stats }];

const stats = $('Calculate Weekly Statistics').first().json;
const aiReport = $input.first().json.text || $input.first().json.output;

let message = `📊 **週間宇宙ステーション観測レポート**\n`;
message += `📅 ${new Date().toLocaleDateString('ja-JP')} 時点\n\n`;

message += `━━━━━━━━━━━━━━━━━━━━\n`;
message += `📈 **統計サマリー**\n`;
message += `━━━━━━━━━━━━━━━━━━━━\n\n`;
message += `🛰️ 検出されたパス: ${stats.totalSightings}回\n`;
message += `👀 観測可能だったパス: ${stats.observableSightings}回\n`;
message += `✅ 成功率: ${stats.successRate}%\n`;
message += `⭐ 平均スコア: ${stats.avgScore}/100\n\n`;

if (stats.bestSighting) {
  message += `━━━━━━━━━━━━━━━━━━━━\n`;
  message += `🏆 **今週のベストパス**\n`;
  message += `━━━━━━━━━━━━━━━━━━━━\n\n`;
  message += `🛰️ ${stats.bestSighting.satellite}\n`;
  message += `📏 ${stats.bestSighting.distance_km}km\n`;
  message += `📊 スコア: ${stats.bestSighting.observation_score}\n\n`;
}

message += `━━━━━━━━━━━━━━━━━━━━\n`;
message += `🤖 **AI分析レポート**\n`;
message += `━━━━━━━━━━━━━━━━━━━━\n\n`;
message += aiReport;

return [{
  json: {
    stats,
    weeklyReport: message
  }
}];

const satelliteData = $('Calculate All Satellites').first().json;
const weatherData = $('Get Weather Conditions').first().json;
const astronautData = $('Get Astronauts in Space').first().json;

// Weather analysis
const weatherMain = weatherData.weather?.[0]?.main || 'Clear';
const cloudiness = weatherData.clouds?.all || 0;
const visibility = weatherData.visibility || 10000;
const sunset = new Date(weatherData.sys?.sunset * 1000);
const sunrise = new Date(weatherData.sys?.sunrise * 1000);
const now = new Date();

// Observation conditions
let observationScore = 100;
let conditions = [];

if (['Rain', 'Snow', 'Thunderstorm'].includes(weatherMain)) {
  observationScore -= 80;
  conditions.push('❌ 悪天候');
} else if (cloudiness > 80) {
  observationScore -= 60;
  conditions.push('☁️ 雲量多い');
} else if (cloudiness > 50) {
  observationScore -= 30;
  conditions.push('🌥️ 部分的に曇り');
} else {
  conditions.push('✨ 晴天');
}

// Time of day analysis
let timeCondition = '';
const hour = now.getHours();
if (hour >= 18 && hour < 21 || hour >= 5 && hour < 7) {
  timeCondition = '🌅 薄明時間帯 - 最高の観測条件！';
  observationScore += 20;
} else if (hour >= 21 || hour < 5) {
  timeCondition = '🌙 夜間 - 良好な観測条件';
} else {
  timeCondition = '☀️ 日中 - 観測困難';
  observationScore -= 40;
}

observationScore = Math.max(0, Math.min(100, observationScore));

// Astronaut info
const issAstronauts = astronautData.people?.filter(p => p.craft === 'ISS') || [];
const tiangongAstronauts = astronautData.people?.filter(p => p.craft === 'Tiangong') || [];

// Photography recommendations
let photoSettings = {};
if (observationScore >= 60) {
  if (hour >= 18 || hour < 6) {
    photoSettings = {
      iso: '1600-3200',
      aperture: 'f/2.8-4',
      shutter: '1/250-1/500秒',
      tips: '三脚使用推奨。追尾撮影がベスト。'
    };
  } else {
    photoSettings = {
      iso: '100-400',
      aperture: 'f/8-11',
      shutter: '1/1000秒以上',
      tips: '日中は望遠鏡+ソーラーフィルター推奨'
    };
  }
}

return [{
  json: {
    ...satelliteData,
    weather: {
      main: weatherMain,
      description: weatherData.weather?.[0]?.description,
      cloudiness,
      visibility,
      temperature: weatherData.main?.temp,
      humidity: weatherData.main?.humidity
    },
    observation: {
      score: observationScore,
      conditions,
      timeCondition,
      canObserve: observationScore >= 40,
      recommendation: observationScore >= 70 ? '🟢 観測推奨' : observationScore >= 40 ? '🟡 観測可能' : '🔴 観測困難'
    },
    astronauts: {
      iss: issAstronauts,
      tiangong: tiangongAstronauts,
      totalInSpace: astronautData.number || 0
    },
    photography: photoSettings
  }
}];
